15: // refreshBasicRolePermissionsInDB ensures basic role permissions are fully derived from in-memory registrations
16: func (s *Service) refreshBasicRolePermissionsInDB(ctx context.Context, rolesSnapshot map[string][]accesscontrol.Permission) error {
17: 	if s.sql == nil || s.seeder == nil {
18: 		return nil
19: 	}
20: 
21: 	run := func(ctx context.Context) error {
22: 		desired := map[accesscontrol.SeedPermission]struct{}{}
23: 		for role, permissions := range rolesSnapshot {
24: 			for _, permission := range permissions {
25: 				desired[accesscontrol.SeedPermission{BuiltInRole: role, Action: permission.Action, Scope: permission.Scope}] = struct{}{}
26: 			}
27: 		}
28: 		s.seeder.SetDesiredPermissions(desired)
29: 		return s.seeder.Seed(ctx)
30: 	}
31: 
32: 	if s.serverLock == nil {
33: 		return run(ctx)
34: 	}
35: 
36: 	var err error
37: 	errLock := s.serverLock.LockExecuteAndRelease(ctx, ossBasicRoleSeedLockName, ossBasicRoleSeedTimeout, func(ctx context.Context) {
38: 		err = run(ctx)
39: 	})
40: 	if errLock != nil {
41: 		return errLock
42: 	}
43: 	return err
44: }
